export function renderLabel(user: { name: string; title: string }): string {
  const name = formatPart(user.name);
  const title = formatPart(user.title);
  return `<span class="text-sm text-gray-600 font-medium">${name} — ${title}</span>`;
}

function formatPart(value: string): string {
  return value.trim();
}
